<?php
namespace App\Models; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\{BelongsTo,HasMany};
class KnowledgeMachine extends Model { protected $fillable=['manufacturer','model_name','variant','product_code','category','summary','supported_refrigerants','technical_specifications','main_functions','is_active','created_by','updated_by']; protected function casts():array{return['supported_refrigerants'=>'array','technical_specifications'=>'array','main_functions'=>'array','is_active'=>'boolean'];} public function notes():HasMany{return $this->hasMany(KnowledgeNote::class);} public function media():HasMany{return $this->hasMany(KnowledgeMedia::class);} public function serviceCodes():HasMany{return $this->hasMany(KnowledgeServiceCode::class);} public function documents():HasMany{return $this->hasMany(KnowledgeDocument::class);} public function creator():BelongsTo{return $this->belongsTo(User::class,'created_by');} public function updater():BelongsTo{return $this->belongsTo(User::class,'updated_by');}}
